1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BLOCK_OF_3_PRICE = 60;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const CLAIM_DEDUCTIBLE = 100;
12	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
13	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	type Item = {
26	  type: string;
27	  cursed?: boolean;
28	  enchantment?: number;
29	  material?: string;
30	};
31	type QuoteStep = { type: "quote"; items: Item[] };
32	type Damage = { itemType: string; amount: number };
33	type Incident = { cause: string; damages: Damage[] };
34	type ClaimStep = { type: "claim"; policy: number; incident: Incident };
35	type Step = QuoteStep | ClaimStep;
36	type Customer = { yearsWithMHPCO: number };
37	type Scenario = { customer?: Customer; steps: Step[] };
38	
39	function groupByType(items: Item[]): Map<string, Item[]> {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	}
48	
49	function isHighlyEnchanted(item: Item): boolean {
50	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
51	}
52	
53	function itemBasePrice(item: Item): number {
54	  const price = BASE_PREMIUMS[item.type];
55	  if (price === undefined) {
56	    throw new Error(`Unknown item type: ${item.type}`);
57	  }
58	  return price;
59	}
60	
61	function itemPriceWithSurcharges(item: Item): number {
62	  const base = itemBasePrice(item);
63	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
64	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
65	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
66	    : 0;
67	  return base + curseSurcharge + highEnchantmentSurcharge;
68	}
69	
70	function sumGroup(type: string, group: Item[], itemPrice: (item: Item) => number): number {
71	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
72	    return COMPONENT_BLOCK_OF_3_PRICE;
73	  }
74	  return group.reduce((sum, item) => sum + itemPrice(item), 0);
75	}
76	
77	function sumItems(items: Item[], itemPrice: (item: Item) => number): number {
78	  return Array.from(groupByType(items)).reduce(
79	    (total, [type, group]) => total + sumGroup(type, group, itemPrice),
80	    0,
81	  );
82	}
83	
84	function calculatePremium(items: Item[], isLoyalCustomer: boolean, isFollowUp: boolean): number {
85	  const policyBase = sumItems(items, itemPriceWithSurcharges);
86	  const unmodifiedBase = sumItems(items, itemBasePrice);
87	  const firstInsuranceSurcharge = unmodifiedBase * FIRST_INSURANCE_RATE;
88	  const loyaltyDiscount = isLoyalCustomer ? unmodifiedBase * LOYALTY_DISCOUNT_RATE : 0;
89	  const followUpDiscount = isFollowUp ? unmodifiedBase * FOLLOW_UP_DISCOUNT_RATE : 0;
90	  return policyBase - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
91	}
92	
93	function reimbursableAmount(damage: Damage, policyItems: Item[]): number {
94	  const item = policyItems.find((i) => i.type === damage.itemType);
95	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
96	    return damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE;
97	  }
98	  return damage.amount;
99	}
100	
101	function damagePayout(damage: Damage, policyItems: Item[]): number {
102	  return Math.max(0, reimbursableAmount(damage, policyItems) - CLAIM_DEDUCTIBLE);
103	}
104	
105	function calculatePayout(incident: Incident, policyItems: Item[]): number {
106	  return incident.damages.reduce((sum, damage) => sum + damagePayout(damage, policyItems), 0);
107	}
108	
109	export function runScenario(
110	  scenario: unknown,
111	): { results: ({ premium: number } | { payout: number })[] } {
112	  const { customer, steps } = scenario as Scenario;
113	  const isLoyalCustomer = (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
114	  let quoteCount = 0;
115	  const results = steps.map((step) => {
116	    if (step.type === "claim") {
117	      const policyStep = steps[step.policy] as QuoteStep;
118	      return { payout: Math.floor(calculatePayout(step.incident, policyStep.items)) };
119	    }
120	    const isFollowUp = quoteCount > 0;
121	    quoteCount++;
122	    return {
123	      premium: Math.ceil(calculatePremium(step.items, isLoyalCustomer, isFollowUp)),
124	    };
125	  });
126	  return { results };
127	}
